SELECT [Sales Cr_Memo Header].No_, [Sales Cr_Memo Header].[Bill-to Customer No_], [Sales Cr_Memo Header].[Bill-to Name], [Sales Cr_Memo Header].[Posting Date], [Sales Cr_Memo Header].[Shortcut Dimension 1 Code], [Sales Cr_Memo Header].[Selling Season Code], [Sales Cr_Memo Header].[Shortcut Dimension 2 Code], [Sales Cr_Memo Header].[Subject 1], [Sales Cr_Memo Header].[Subject 2], [Sales Cr_Memo Header].[Salesperson Code], [Sales Cr_Memo Header].[Area Manager Code], Avg(Val([Subject 1 Commission _])) AS ProvvigioneSogg1, Avg(Val([Subject 2 Commission _])) AS ProvvigioneSogg2, Avg(Val([Salesperson Commission _])) AS ProvvigioneAgente, Avg(Val([Area Manager Commission _])) AS ProvvigioneAreamanager
FROM [Sales Cr_Memo Line] RIGHT JOIN [Sales Cr_Memo Header] ON [Sales Cr_Memo Line].[Document No_] = [Sales Cr_Memo Header].No_
WHERE ((([Sales Cr_Memo Line].type)=19 Or ([Sales Cr_Memo Line].type)=20 Or ([Sales Cr_Memo Line].type)=1))
GROUP BY [Sales Cr_Memo Header].No_, [Sales Cr_Memo Header].[Bill-to Customer No_], [Sales Cr_Memo Header].[Bill-to Name], [Sales Cr_Memo Header].[Posting Date], [Sales Cr_Memo Header].[Shortcut Dimension 1 Code], [Sales Cr_Memo Header].[Selling Season Code], [Sales Cr_Memo Header].[Shortcut Dimension 2 Code], [Sales Cr_Memo Header].[Subject 1], [Sales Cr_Memo Header].[Subject 2], [Sales Cr_Memo Header].[Salesperson Code], [Sales Cr_Memo Header].[Area Manager Code];

